editorial:
**Naive**: track min and max separately ⇒ 2(n-1) comparisons.

**Divide & conquer**: split, recurse on halves, combine with **2 comparisons** to merge two (min,max) pairs.

```javascript
function tournamentMinMax(scores) {
  function helper(lo, hi) {
    if (lo === hi) return [scores[lo], scores[lo]];
    if (hi - lo === 1) {
      return scores[lo] < scores[hi]
        ? [scores[lo], scores[hi]]
        : [scores[hi], scores[lo]];
    }
    const mid = (lo + hi) >> 1;
    const [lMin, lMax] = helper(lo, mid);
    const [rMin, rMax] = helper(mid + 1, hi);
    return [Math.min(lMin, rMin), Math.max(lMax, rMax)];
  }
  return helper(0, scores.length - 1);
}
```

