**Why straight merge can't piggyback**: the comparison `a[i] > 2*a[j]` differs from the merge comparison `a[i] > a[j]`. Run a separate counting pass before merging.

```javascript
function reversePairs(nums) {
  const a = nums.slice();
  function sort(lo, hi) {
    if (lo >= hi) return 0;
    const mid = (lo + hi) >> 1;
    let count = sort(lo, mid) + sort(mid + 1, hi);
    // count cross reverse pairs
    let j = mid + 1;
    for (let i = lo; i <= mid; i++) {
      while (j <= hi && a[i] > 2 * a[j]) j++;
      count += (j - mid - 1);
    }
    // merge
    const tmp = []; let p = lo, q = mid + 1;
    while (p <= mid && q <= hi) {
      if (a[p] <= a[q]) tmp.push(a[p++]); else tmp.push(a[q++]);
    }
    while (p <= mid) tmp.push(a[p++]);
    while (q <= hi) tmp.push(a[q++]);
    for (let k = 0; k < tmp.length; k++) a[lo + k] = tmp[k];
    return count;
  }
  return sort(0, a.length - 1);
}
```

