editorial:
**Divide**: split building array into halves.
**Conquer**: recursively compute skyline of each half (each is a list of `[x, y]` key points).
**Merge**: sweep both lists with two pointers, maintaining current heights h1 and h2; at each next x boundary, emit `[x, max(h1, h2)]` if it differs from the previous emitted height.

```javascript
function getSkyline(buildings) {
  function build(lo, hi) {
    if (lo > hi) return [];
    if (lo === hi) {
      const [l, r, h] = buildings[lo];
      return [[l, h], [r, 0]];
    }
    const mid = (lo + hi) >> 1;
    return merge(build(lo, mid), build(mid + 1, hi));
  }
  function merge(A, B) {
    const out = []; let i = 0, j = 0, h1 = 0, h2 = 0, prev = 0;
    while (i < A.length && j < B.length) {
      let x;
      if (A[i][0] < B[j][0]) { x = A[i][0]; h1 = A[i][1]; i++; }
      else if (A[i][0] > B[j][0]) { x = B[j][0]; h2 = B[j][1]; j++; }
      else { x = A[i][0]; h1 = A[i][1]; h2 = B[j][1]; i++; j++; }
      const cur = Math.max(h1, h2);
      if (cur !== prev) { out.push([x, cur]); prev = cur; }
    }
    while (i < A.length) { if (A[i][1] !== prev) { out.push(A[i]); prev = A[i][1]; } i++; }
    while (j < B.length) { if (B[j][1] !== prev) { out.push(B[j]); prev = B[j][1]; } j++; }
    return out;
  }
  return build(0, buildings.length - 1);
}
```

**Recurrence**: T(n) = 2·T(n/2) + Θ(n) — merge is linear in the combined skyline size.

**Master theorem**: a=2, b=2, f(n)=Θ(n), Case 2 ⇒ T(n) = Θ(n log n).

The heap-based sweep approach is also Θ(n log n) but D&C is the textbook divide-merge formulation.
